.ico_defeat_a { transform-origin: 12px 12px; transform: translate(0, 0); animation: ani_defeat_a 1s ease 1; }
							.ico_defeat_b { transform-origin: 12px 12px; transform: translate(0, 0); animation: ani_defeat_b 1s ease 1; }
							.ico_defeat_c { transform-origin: 12px 12px; transform: translate(0, 0); animation: ani_defeat_c 1s ease 1; }
							.ico_defeat_d { transform-origin: 12px 12px; transform: translate(0, 0); animation: ani_defeat_d 1s ease 1; }
							@keyframes ani_defeat_a { 0% { transform: translate(8px, 8px); } 50% { transform: translate(0, 0); } 100% { transform: translate(0, 0); } }
							@keyframes ani_defeat_b { 0% { transform: translate(-8px, 8px); } 50% { transform: translate(0, 0); } 100% { transform: translate(0, 0); } }
							@keyframes ani_defeat_c { 0% { transform: translate(-8px, -8px); } 50% { transform: translate(0, 0); } 100% { transform: translate(0, 0); } }
							@keyframes ani_defeat_d { 0% { transform: translate(8px, -8px); } 50% { transform: translate(0, 0); } 100% { transform: translate(0, 0); } }

.ico_defeat_d_top { transform-origin: 12px 12px; transform: translate(0, 0); animation: ani_defeat_d_top 1s ease 1; }
							.ico_defeat_d_bottom { transform-origin: 12px 12px; transform: translate(0, 0); animation: ani_defeat_d_bottom 1s ease 1; }
							.ico_defeat_d_left { transform-origin: 12px 12px; transform: translate(0, 0); animation: ani_defeat_d_left 1s ease 1; }
							.ico_defeat_d_right { transform-origin: 12px 12px; transform: translate(0, 0); animation: ani_defeat_d_right 1s ease 1; }
							@keyframes ani_defeat_d_top { 0% { opacity: 0; transform: translate(0, -4px); } 50% { opacity: 0; transform: translate(0, -4px); } 75% { opacity: 1; transform: translate(0, -4px); } 100% { opacity: 1; transform: translate(0, 0); } }
							@keyframes ani_defeat_d_bottom { 0% { opacity: 0; transform: translate(0, 4px); } 50% { opacity: 0; transform: translate(0, 4px); } 75% { opacity: 1; transform: translate(0, 4px); } 100% { opacity: 1; transform: translate(0, 0); } }
							@keyframes ani_defeat_d_left { 0% { opacity: 0; transform: translate(-4px, 0); } 50% { opacity: 0; transform: translate(-4px, 0); } 75% { opacity: 1; transform: translate(-4px, 0); } 100% { opacity: 1; transform: translate(0, 0); } }
							@keyframes ani_defeat_d_right { 0% { opacity: 0; transform: translate(4px, 0); } 50% { opacity: 0; transform: translate(4px, 0); } 75% { opacity: 1; transform: translate(4px, 0); } 100% { opacity: 1; transform: translate(0, 0); } }

.ico_defeat_cross { transform-origin: 12px 12px; transform: rotate(45deg); animation: ani_defeat_cross 1s ease 1; }
							@keyframes ani_defeat_cross {
								0% { transform: rotate(0deg); }
								50% { transform: rotate(0deg); }
								75% { transform: rotate(45deg); }
								100% { transform: rotate(45deg); }
							}
							.ico_defeat_cross_a { transform-origin: 12px 12px; animation: ani_defeat_cross_a 1s ease 1; }
							.ico_defeat_cross_b { transform-origin: 12px 12px; animation: ani_defeat_cross_b 1s ease 1; }
							@keyframes ani_defeat_cross_a {
								0% { transform: scale(0, 1); }
								50% { transform: scale(1, 1); }
								100% { transform: scale(1, 1); }
							}
							@keyframes ani_defeat_cross_b {
								0% { transform: scale(1, 0); }
								50% { transform: scale(1, 1); }
								100% { transform scale(1, 1); }
							}

.ico_defeat_heart { transform-origin: 12px 12px; animation: ani_defeat_heart 1s ease 1; }
							@keyframes ani_defeat_heart {
								0% { transform: scale(0, 0); }
								20% { transform: scale(1.2, 1.5); }
								40% { transform: scale(0.9, 0.8); }
								60% { transform: scale(1.05, 1.2); }
								80% { transform: scale(1.1, 0.9); }
								100% { transform: scale(1, 1); }
							}
							.ico_defeat_heart_a { transform-origin: 12px 12px; transform: translate(0, 0); animation: ani_defeat_heart_a 1s ease 1; }
							.ico_defeat_heart_b { transform-origin: 12px 12px; transform: translate(0, 0); animation: ani_defeat_heart_b 1s ease 1; }
							@keyframes ani_defeat_heart_a {
								0% { transform: translate(0, 2px); }
								50% { transform: translate(0, 2px); }
								75% { transform: translate(0, 0); }
								100% { transform: translate(0, 0); }
							}
							@keyframes ani_defeat_heart_b {
								0% { transform: translate(0, -2px); }
								50% { transform: translate(0, -2px); }
								75% { transform: translate(0, 0); }
								100% { transform: translate(0, 0); }
							}

